class RecalibrationRecommendationResponse(BaseModel):
    """
    Response model for recalibration recommendations.

    When a parameter changes, this response provides a prioritized list
    of calibration tasks that should be re-run to maintain consistency.

    Attributes
    ----------
    source_entity_id : str
        The changed parameter that triggered recommendations
    source_parameter_name : str
        Name of the changed parameter
    source_qid : str
        Qubit/coupling ID of the changed parameter
    recommended_tasks : list[RecommendedTaskResponse]
        Prioritized list of tasks to re-run
    total_affected_parameters : int
        Total count of downstream parameters affected
    max_depth_reached : int
        Depth of impact graph traversed
    """

    source_entity_id: Annotated[str, Field(title="Source Entity Id")]
    """
    Changed parameter entity ID
    """
    source_parameter_name: Annotated[str, Field(title="Source Parameter Name")] = ""
    """
    Changed parameter name
    """
    source_qid: Annotated[str, Field(title="Source Qid")] = ""
    """
    Changed parameter QID
    """
    recommended_tasks: Annotated[
        list[RecommendedTaskResponse] | None, Field(title="Recommended Tasks")
    ] = None
    """
    Prioritized task recommendations
    """
    total_affected_parameters: Annotated[int, Field(title="Total Affected Parameters")] = 0
    """
    Total downstream parameters affected
    """
    max_depth_reached: Annotated[int, Field(title="Max Depth Reached")] = 0
    """
    Impact graph depth traversed
    """


class SeedImportRequest(BaseModel):
    """
    Request to import seed parameters from qubex or manual input.

    Attributes
    ----------
    chip_id : str
        Target chip ID (e.g., "64Qv3")
    source : SeedImportSource
        Source of the parameters
    parameters : list[str] | None
        List of parameter names to import. If None, imports all available.
    qids : list[str] | None
        List of qubit IDs to import. If None, imports all available.
    manual_data : dict[str, dict[str, Any]] | None
        Manual data when source is MANUAL.
        Format: {"parameter_name": {"Q0": value, "Q1": value, ...}}
    """

    chip_id: Annotated[str, Field(title="Chip Id")]
    """
    Target chip ID
    """
    source: SeedImportSource = SeedImportSource.qubex_params
    """
    Source of parameters
    """
    parameters: Annotated[
        list[str] | None,
        Field(
            examples=[["qubit_frequency", "readout_amplitude", "control_amplitude"]],
            title="Parameters",
        ),
    ] = None
    """
    Parameter names to import (None = all available)
    """
    qids: Annotated[list[str] | None, Field(examples=[["Q00", "Q01", "Q02"]], title="Qids")] = None
    """
    Qubit IDs to import (None = all available)
    """
    manual_data: Annotated[dict[str, dict[str, Any]] | None, Field(title="Manual Data")] = None
    """
    Manual data when source is MANUAL
    """


